import React, { useState } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

const Navbar = () => {
  const { user, logout, isAuthenticated } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [menuOpen, setMenuOpen] = useState(false);

  const handleLogout = () => {
    logout();
    navigate("/");
    setMenuOpen(false);
  };

  const isActive = (path) => location.pathname === path ? "active" : "";

  return (
    <nav className="navbar navbar-expand-lg navbar-dark-custom sticky-top" style={{
      background: "rgba(15,15,26,0.97)",
      backdropFilter: "blur(16px)",
      borderBottom: "1px solid #2a2a4a"
    }}>
      <div className="container">
        {/* Brand Logo */}
        <Link className="navbar-brand d-flex align-items-center gap-2 fw-bold fs-5" to="/">
          <span style={{
            fontFamily: "JetBrains Mono, monospace",
            background: "rgba(108,99,255,0.15)",
            color: "#6c63ff",
            padding: "3px 10px",
            borderRadius: "6px",
            fontSize: "0.95rem"
          }}>{"</>"}</span>
          <span style={{ color: "#e8e8f0" }}>CodeLearn</span>
        </Link>

        {/* Mobile Toggle */}
        <button
          className="navbar-toggler border-0"
          type="button"
          onClick={() => setMenuOpen(!menuOpen)}
          style={{ color: "#9999bb" }}
        >
          <i className={`bi ${menuOpen ? "bi-x-lg" : "bi-list"} fs-5`}></i>
        </button>

        {/* Nav Links */}
        <div className={`collapse navbar-collapse ${menuOpen ? "show" : ""}`}>
          <ul className="navbar-nav me-auto mb-2 mb-lg-0">
            <li className="nav-item">
              <Link
                className={`nav-link px-3 ${isActive("/")}`}
                to="/"
                onClick={() => setMenuOpen(false)}
                style={{ color: isActive("/") ? "#6c63ff" : "#9999bb", fontWeight: 500 }}
              >
                <i className="bi bi-grid me-1"></i> Courses
              </Link>
            </li>
            {isAuthenticated && (
              <li className="nav-item">
                <Link
                  className={`nav-link px-3 ${isActive("/my-courses")}`}
                  to="/my-courses"
                  onClick={() => setMenuOpen(false)}
                  style={{ color: isActive("/my-courses") ? "#6c63ff" : "#9999bb", fontWeight: 500 }}
                >
                  <i className="bi bi-journal-bookmark me-1"></i> My Learning
                </Link>
              </li>
            )}
          </ul>

          {/* Auth Buttons */}
          <div className="d-flex align-items-center gap-2">
            {isAuthenticated ? (
              <>
                <div className="d-flex align-items-center gap-2 me-2">
                  <div style={{
                    width: 34, height: 34, borderRadius: "50%",
                    background: "linear-gradient(135deg, #6c63ff, #ff6584)",
                    display: "flex", alignItems: "center", justifyContent: "center",
                    fontWeight: 700, fontSize: "0.85rem", color: "white"
                  }}>
                    {user?.name?.charAt(0).toUpperCase()}
                  </div>
                  <span style={{ color: "#9999bb", fontSize: "0.9rem" }}>
                    {user?.name?.split(" ")[0]}
                  </span>
                </div>
                <button
                  className="btn btn-sm"
                  onClick={handleLogout}
                  style={{ border: "1px solid #2a2a4a", color: "#9999bb", borderRadius: 8 }}
                >
                  <i className="bi bi-box-arrow-right me-1"></i>Logout
                </button>
              </>
            ) : (
              <>
                <Link
                  to="/login"
                  className="btn btn-sm"
                  onClick={() => setMenuOpen(false)}
                  style={{ border: "1px solid #2a2a4a", color: "#9999bb", borderRadius: 8 }}
                >
                  Log In
                </Link>
                <Link
                  to="/signup"
                  className="btn btn-sm btn-primary-custom"
                  onClick={() => setMenuOpen(false)}
                  style={{ background: "#6c63ff", color: "white", border: "none", borderRadius: 8, fontWeight: 600 }}
                >
                  Sign Up
                </Link>
              </>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
